# Using Methods of Composed Objects

You can call methods on composed objects through the parent object:

```python
class Engine:
    def __init__(self, horsepower):
        self.__horsepower = horsepower  # name-mangled private attribute

    @property
    def horsepower(self):
        return self.__horsepower

    def start(self):
        return f"Engine with {self.__horsepower}hp started"

class Car:
    def __init__(self, brand, engine):
        self._brand = brand       # gentleman's code — protected by convention
        self._engine = engine     # Car HAS-A Engine

    def ignition(self):
        return self._engine.start()  # Call method of composed object

engine = Engine(200)
car = Car("Toyota", engine)
print(car.ignition())         # Output: Engine with 200hp started
print(engine.horsepower)      # Output: 200  (accessed via @property)
```

This chains method calls through the object hierarchy. Notice:
- `self.__horsepower` inside `Engine` — only `Engine` methods can access it directly
- `self._engine` inside `Car` — gentle warning not to access from outside, but not enforced

# Managing Collections of Objects

You can store multiple objects in a list:

```python
class Student:
    def __init__(self, name, student_id):
        self.name = name
        self.student_id = student_id

class Course:
    def __init__(self, course_name):
        self.course_name = course_name
        self.students = []  # List of students

    def add_student(self, student):
        self.students.append(student)

    def list_students(self):
        for student in self.students:
            print(f"{student.name} ({student.student_id})")

course = Course("Python 101")
course.add_student(Student("Alice", "S001"))
course.add_student(Student("Bob", "S002"))
course.list_students()
```

The `Course` object manages a list of `Student` objects, allowing you to work with collections of related items.

# Working with Collections

You can iterate over lists of objects to access their attributes:

```python
class Item:
    def __init__(self, name, price):
        self.name = name
        self.price = price

class ShoppingCart:
    def __init__(self):
        self.items = []

    def add_item(self, item):
        self.items.append(item)

    def total_price(self):
        total = 0
        for item in self.items:
            total += item.price
        return total

    def display_items(self):
        for item in self.items:
            print(f"{item.name}: ${item.price}")

cart = ShoppingCart()
cart.add_item(Item("Apple", 1.50))
cart.add_item(Item("Banana", 0.75))
cart.display_items()
print(f"Total: ${cart.total_price()}")  # Output: Total: $2.25
```

Iterating allows you to perform operations across all objects in a collection.

# Using Dictionaries to Organize Objects

Dictionaries allow you to store objects with meaningful keys:

```python
class Employee:
    def __init__(self, name, department):
        self.name = name
        self.department = department

class Company:
    def __init__(self, company_name):
        self.company_name = company_name
        self.employees = {}  # Dictionary of employees

    def hire(self, emp_id, employee):
        self.employees[emp_id] = employee

    def find_employee(self, emp_id):
        return self.employees.get(emp_id)

company = Company("TechCorp")
company.hire("E001", Employee("Alice", "Engineering"))
company.hire("E002", Employee("Bob", "Sales"))

emp = company.find_employee("E001")
print(f"{emp.name} works in {emp.department}")  # Output: Alice works in Engineering
```

Dictionaries are ideal when you need to quickly find objects by a unique identifier.

